import { Component } from '@angular/core';
import { RouterLink } from '@angular/router';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [RouterLink],
  template: `
    <section class="hero">
      <h1>Hi, I'm <span class="accent">Your Name</span></h1>
      <p>I build thoughtful digital products. Here's my work.</p>
      <a routerLink="/projects" class="btn btn-primary">View Projects</a>
    </section>
  `
})
export class HomeComponent {}
